      0:{q:"За что должны держаться стоящие пассажиры?",options:["Совсем ни за что","За поручень или ремень","За самого водителя","За оконное стекло"],explanation:"Стоящие пассажиры должны держаться за поручень или ремень."},
      1:{q:"Сиденья и их каркасы в автобусе должны быть:",options:["Расшатанными","Закреплёнными и прочными","Полностью снятыми","Мокрыми внутри"],explanation:"Сиденья и каркасы должны быть закреплены и прочны."},
      2:{q:"Проход автобуса должен быть:",options:["Заставлен сумками","Свободным","Мокрым и скользким","Тёмным"],explanation:"Держи проход свободным, чтобы пассажиры могли двигаться и выходить."},
      3:{q:"Водитель автобуса должен разгоняться и тормозить:",options:["Резко и быстро","Плавно и мягко","С закрытыми глазами","Только под гору"],explanation:"Плавное мягкое торможение держит пассажиров в безопасности и комфорте."},
      4:{q:"Если пассажиру плохо или ЧП, водитель должен:",options:["Просто игнорировать","Безопасно встать и помочь","Быстро ускориться","Открыть люк на крыше"],explanation:"Остановись в безопасном месте и при необходимости вызови помощь."},
      5:{q:"Пассажиры должны держать руки и головы:",options:["Высунув в окна","Внутри автобуса","На водителе","Высунув за дверь"],explanation:"Пассажиры держат руки и головы внутри автобуса."},
      6:{q:"Аварийное оснащение автобуса — это огнетушитель и:",options:["Маленький плоский ТВ","Выходы и предупреждающие знаки","Холодильник с напитками","Простые шторки на окнах"],explanation:"В автобусе также должны быть аварийные выходы и предупреждающие устройства."},
      7:{q:"Подъезжая к остановке, нужно:",options:["Промчаться мимо неё","Снизить скорость и аккуратно подъехать","Встать прямо в полосе","Просто посигналить громко"],explanation:"Снизь скорость и аккуратно подъедь, чтобы пассажиры сели."},
      8:{q:"Максимальное число стоящих может устанавливаться:",options:["Настроением водителя","Правилами штата и местными","Громким радио в кабине","Плохой погодой дня"],explanation:"Правила штата и местные могут ограничивать число стоящих."},
